    offset: -0.2
  },
  LANDSAT9: {
    id: 'LANDSAT/LC09/C02/T1_L2',
    name: 'Landsat-9',
    startDate: '2021-10-31',
    bands: {
      blue: 'SR_B2',
      green: 'SR_B3',
      red: 'SR_B4',
      nir: 'SR_B5',
